    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(size: number) {
            this.parent = Array.from({ length: size }, (_, i) => i);
            this.rank = Array(size).fill(0);
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false;
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize Union-Find
    const uf = new UnionFind(n);

    // Keep track of the maximum cost
    let maxCost = 0;

    // Process edges in order of increasing weight
    for (const [u, v, w] of edges) {
        // Check if the nodes are already connected
        if (uf.find(u) !== uf.find(v)) {
            // Union the nodes
            uf.union(u, v);
            // Update the maximum cost
            maxCost = Math.max(maxCost, w);
        }
    }

    // If k is 1, the maximum cost is the maximum edge weight
    if (k === 1) {
        return maxCost;
    }

    // If k is greater than the number of nodes, return 0
    if (k >= n) {
        return 0;
    }

    // We need to split the graph into k components
    // So we need to remove (number of components - k) edges
    // We will keep track of the number of components
    let components = n;
    let result = 0;

